def merge_dicts(a: dict[str, int], b: dict[str, int]) -> dict[str, int]:
    result = a.copy()
    for key, value in b.items():
        result[key] = result.get(key, 0) + value
    return result

x: dict[str, int] = {'a': 1, 'b': 2}
y: dict[str, int] = {'b': 3, 'c': 4}
print(merge_dicts(x, y))
